import{c as e,Q as l,j as d,m as o}from"./chunks/framework.rlpw0eGz.js";const g=JSON.parse('{"title":"Registry Reference Guide","description":"","frontmatter":{},"headers":[],"relativePath":"Registry_Reference.md","filePath":"Registry_Reference.md"}'),a={name:"Registry_Reference.md"};function i(r,t,s,n,c,f){return l(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="registry-reference-guide" tabindex="-1">Registry Reference Guide <a class="header-anchor" href="#registry-reference-guide" aria-label="Permalink to &quot;Registry Reference Guide&quot;">​</a></h1><p>This document provides total transparency into the exact registry keys and values modified by the <strong>Windows-Optimisations Framework</strong>. This is intended for power users, system administrators, and security auditors who want to know exactly what is happening under the hood.</p><hr><h2 id="_1-shell-ui-cleanup" tabindex="-1">1. Shell &amp; UI Cleanup <a class="header-anchor" href="#_1-shell-ui-cleanup" aria-label="Permalink to &quot;1. Shell &amp; UI Cleanup&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Tweak</th><th style="text-align:left;">Registry Path</th><th style="text-align:left;">Value Name</th><th style="text-align:left;">Target Value</th></tr></thead><tbody><tr><td style="text-align:left;">Disable Copilot</td><td style="text-align:left;"><code>HKCU:\\Software\\Policies\\Microsoft\\Windows\\WindowsCopilot</code></td><td style="text-align:left;"><code>TurnOffWindowsCopilot</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Disable Widgets</td><td style="text-align:left;"><code>HKLM:\\SOFTWARE\\Policies\\Microsoft\\Dsh</code></td><td style="text-align:left;"><code>AllowNewsAndInterests</code></td><td style="text-align:left;"><code>0</code></td></tr><tr><td style="text-align:left;">Hide Recommended</td><td style="text-align:left;"><code>HKLM:\\SOFTWARE\\Policies\\Microsoft\\Windows\\Explorer</code></td><td style="text-align:left;"><code>HideRecommendedSection</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Disable Toasts</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\PushNotifications</code></td><td style="text-align:left;"><code>ToastEnabled</code></td><td style="text-align:left;"><code>0</code></td></tr></tbody></table><h2 id="_2-explorer-search" tabindex="-1">2. Explorer &amp; Search <a class="header-anchor" href="#_2-explorer-search" aria-label="Permalink to &quot;2. Explorer &amp; Search&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Tweak</th><th style="text-align:left;">Registry Path</th><th style="text-align:left;">Value Name</th><th style="text-align:left;">Target Value</th></tr></thead><tbody><tr><td style="text-align:left;">Show Hidden Files</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Advanced</code></td><td style="text-align:left;"><code>Hidden</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Show Extensions</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Advanced</code></td><td style="text-align:left;"><code>HideFileExt</code></td><td style="text-align:left;"><code>0</code></td></tr><tr><td style="text-align:left;">Launch to This PC</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Advanced</code></td><td style="text-align:left;"><code>LaunchTo</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Compact View</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Advanced</code></td><td style="text-align:left;"><code>UseCompactMode</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Classic Context Menu</td><td style="text-align:left;"><code>HKCU:\\Software\\Classes\\CLSID\\{86ca1aa0-34aa-4e8b-a509-50c905bae2a2}\\InprocServer32</code></td><td style="text-align:left;"><em>(Default)</em></td><td style="text-align:left;"><em>(Empty)</em></td></tr><tr><td style="text-align:left;">Disable Web Search</td><td style="text-align:left;"><code>HKCU:\\Software\\Policies\\Microsoft\\Windows\\Explorer</code></td><td style="text-align:left;"><code>DisableSearchBoxSuggestions</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Disable Highlights</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\SearchSettings</code></td><td style="text-align:left;"><code>IsDynamicSearchBoxEnabled</code></td><td style="text-align:left;"><code>0</code></td></tr></tbody></table><h2 id="_3-privacy-telemetry-sync-clipboard" tabindex="-1">3. Privacy (Telemetry, Sync, Clipboard) <a class="header-anchor" href="#_3-privacy-telemetry-sync-clipboard" aria-label="Permalink to &quot;3. Privacy (Telemetry, Sync, Clipboard)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Tweak</th><th style="text-align:left;">Registry Path</th><th style="text-align:left;">Value Name</th><th style="text-align:left;">Target Value</th></tr></thead><tbody><tr><td style="text-align:left;">Disable Diagnostic Data</td><td style="text-align:left;"><code>HKLM:\\SOFTWARE\\Policies\\Microsoft\\Windows\\DataCollection</code></td><td style="text-align:left;"><code>AllowTelemetry</code></td><td style="text-align:left;"><code>0</code></td></tr><tr><td style="text-align:left;">Disable Tailored Exp.</td><td style="text-align:left;"><code>HKCU:\\Software\\Policies\\Microsoft\\Windows\\CloudContent</code></td><td style="text-align:left;"><code>DisableTailoredExperiencesWithDiagnosticData</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Disable Activity History</td><td style="text-align:left;"><code>HKLM:\\SOFTWARE\\Policies\\Microsoft\\Windows\\System</code></td><td style="text-align:left;"><code>PublishUserActivities</code></td><td style="text-align:left;"><code>0</code></td></tr><tr><td style="text-align:left;">Disable Clipboard Hist.</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Clipboard</code></td><td style="text-align:left;"><code>EnableClipboardHistory</code></td><td style="text-align:left;"><code>0</code></td></tr><tr><td style="text-align:left;">Disable Cloud Clipboard</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Clipboard</code></td><td style="text-align:left;"><code>EnableCloudClipboard</code></td><td style="text-align:left;"><code>0</code></td></tr><tr><td style="text-align:left;">Disable Camera (Lock)</td><td style="text-align:left;"><code>HKLM:\\SOFTWARE\\Policies\\Microsoft\\Windows\\Personalization</code></td><td style="text-align:left;"><code>NoLockScreenCamera</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Disable Camera (Apps)</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\CapabilityAccessManager\\ConsentStore\\webcam</code></td><td style="text-align:left;"><code>Value</code></td><td style="text-align:left;"><code>Deny</code></td></tr></tbody></table><h2 id="_4-hardware-power" tabindex="-1">4. Hardware &amp; Power <a class="header-anchor" href="#_4-hardware-power" aria-label="Permalink to &quot;4. Hardware &amp; Power&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Tweak</th><th style="text-align:left;">Registry Path</th><th style="text-align:left;">Value Name</th><th style="text-align:left;">Target Value</th></tr></thead><tbody><tr><td style="text-align:left;">Disable Hibernation</td><td style="text-align:left;"><code>HKLM:\\System\\CurrentControlSet\\Control\\Power</code></td><td style="text-align:left;"><code>HibernateEnabled</code></td><td style="text-align:left;"><code>0</code></td></tr><tr><td style="text-align:left;">Enable Game Mode</td><td style="text-align:left;"><code>HKCU:\\Software\\Microsoft\\GameBar</code></td><td style="text-align:left;"><code>AutoGameModeEnabled</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Enable HAGS</td><td style="text-align:left;"><code>HKLM:\\SYSTEM\\CurrentControlSet\\Control\\GraphicsDrivers</code></td><td style="text-align:left;"><code>HwSchMode</code></td><td style="text-align:left;"><code>2</code></td></tr><tr><td style="text-align:left;">Disable Driver Updates</td><td style="text-align:left;"><code>HKLM:\\SOFTWARE\\Policies\\Microsoft\\Windows\\WindowsUpdate</code></td><td style="text-align:left;"><code>ExcludeWUDriversInQualityUpdate</code></td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;">Disable Delivery Opt.</td><td style="text-align:left;"><code>HKLM:\\SOFTWARE\\Policies\\Microsoft\\Windows\\DeliveryOptimization</code></td><td style="text-align:left;"><code>DODownloadMode</code></td><td style="text-align:left;"><code>0</code></td></tr></tbody></table><hr><p><strong>Note:</strong> Many other modifications in this framework are executed via <code>powercfg</code>, <code>schtasks</code>, <code>Get-Service</code>, and <code>Get-AppxPackage</code>, which do not rely directly on raw registry key injection. Those operations are documented within their respective <code>.ps1</code> scripts.</p>',13)])])}const x=e(a,[["render",i]]);export{g as __pageData,x as default};
